  ensures a * c <= b * c
{}

lemma CeilDivLower(a: int, c: int)
  requires a >= 1 && c >= 1
  ensures ((a + c - 1) / c) * c >= a
  ensures (a + c - 1) / c >= 0
{
  var q := (a + c - 1) / c;
  var r := (a + c - 1) % c;
  assert q * c + r == a + c - 1;
  assert r >= 0;
  // q * c = a + c - 1 - r >= a + c - 1 - (c - 1) = a
}

lemma CeilDivMinimal(a: int, c: int, x: int)
  requires a >= 1 && c >= 1 && x >= 0 && x * c >= a
  ensures x >= (a + c - 1) / c
{
